        textAlign: 'center',
        maxWidth: '400px',
        width: '100%'
      }}>
        <h1 style={{ fontSize: '1.875rem', fontWeight: 'bold', marginBottom: '1.5rem', color: '#1f2937' }}>
          Live Shared Counter
        </h1>

        <div style={{
          fontSize: '4.5rem',
          fontWeight: '800',
          color: '#2563eb',
          margin: '2rem 0'
        }} id="counter-value">
          {count.value}
        </div>

        <div style={{ display: 'flex', gap: '1rem', justifyContent: 'center' }}>
          <button
            onClick$={() => mutate(-1)}
            style={{
              padding: '0.75rem 1.5rem',
